#include<bits/stdc++.h>
using namespace std;

int dp[504][504][504];

int findMinCost(vector<vector<int>> &boards, int lastNotRemoved, int totalRemoved, int current, int d, int m){
	if(dp[lastNotRemoved][totalRemoved][current] != -1){
		return dp[lastNotRemoved][totalRemoved][current];
	}
	int currentCost = (current > 0) ? boards[lastNotRemoved][1] * (boards[current][0] - boards[current - 1][0]) : 0;
	if(boards[current][0] == d){
		return currentCost;
	}
	int minCost = findMinCost(boards, current, totalRemoved, current + 1, d, m);
	if(totalRemoved < m){
		minCost = min(minCost, findMinCost(boards, lastNotRemoved, totalRemoved + 1, current + 1, d, m));
	}
	return dp[lastNotRemoved][totalRemoved][current] = (minCost + currentCost);
}

int main(){
	memset(dp, -1, sizeof(dp));
	int n, d, m;
	cin >> n >> d >> m;
	vector<vector<int>> boards(n, vector<int>(2));
	for(auto &board:boards){
		cin >> board[0];
	}
	for(auto &board:boards){
		cin >> board[1];
	}
	boards.push_back({d, 0});
	sort(boards.begin(), boards.end());
	cout << findMinCost(boards, 0, 0, 0, d, m) << endl;
}
